function buildQuery(block) {
  let columns = block.columns.join(", ");
  let distinct_col = block.distinct_col;

  return `
    SELECT ${columns}
    FROM ${block.table_name}
    ORDER BY ${block.order_by_column} ${block.order_by}
    LIMIT ${block.record_count};
  `;
}

