import { useEffect, useState, useMemo } from "react";
import "./Cards.css";

interface ApiResponse {
  status: string;
  results: MetricResult[];
}

interface MetricResult {
  metric_name: string[];
  field_names: string[];
  data: Record<string, any>[];
  category: string[];
}

function formatValue(key: string, value: any) {
  if (value == null) return "-";

  if (typeof value === "string" && (value.endsWith("Z") || key.toLowerCase().includes("date") || key.toLowerCase().includes("time"))) {
    const d = new Date(value);
    if (!isNaN(d.getTime())) return d.toLocaleString();
  }

  if (typeof value === "number") return value;

  if (typeof value === "string" && !isNaN(Number(value))) {
    const n = Number(value);
    return n % 1 === 0 ? n : n.toFixed(2);
  }

  return String(value);
}

export default function UI() {
  const [metrics, setMetrics] = useState<MetricResult[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState("all");

  // ---------- useEffect (runs once)
  useEffect(() => {
    async function load() {
      try {
        const res = await fetch("http://localhost:3000/api/cards");
        const json: ApiResponse = await res.json();
        setMetrics(json.results || []);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    load();
  }, []);

  // ---------- Always compute categories (never inside if)
  const categories = useMemo(() => {
    if (!metrics || metrics.length === 0) return ["all"];

    const all = metrics.flatMap((m) => m.category || []);
    return ["all", ...Array.from(new Set(all))];
  }, [metrics]);

  // ---------- Always compute filtered metrics (never inside if)
  const filteredMetrics = useMemo(() => {
    if (selectedCategory === "all") return metrics;
    return metrics.filter((m) => (m.category || []).includes(selectedCategory));
  }, [metrics, selectedCategory]);

  // ---------- Render phase (safe)
  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  return (
    <div>
      <h1 className="dashboard-title">Dashboard</h1>

      {/* Category Filter */}
      <div className="filter-bar">
        <label>Filter by Category: </label>
        <select value={selectedCategory} onChange={(e) => setSelectedCategory(e.target.value)}>
          {categories.map((c) => (
            <option key={c} value={c}>
              {c}
            </option>
          ))}
        </select>
      </div>

      {/* Cards */}
      <div className="cards-grid">
        {filteredMetrics.map((metric, i) => {
          const title = metric.metric_name?.[0] || "Metric";
          const subtitle = metric.metric_name?.slice(1).join(" • ");
          const row = metric.data?.[0] || {};

          return (
            <div className="card" key={i}>
              <div className="card-header">
                <p className="card-title">{title}</p>
                {subtitle && <p className="card-subtitle">{subtitle}</p>}
                <p>Category: {metric.category || []}</p>
              </div>

              <div className="card-body">
                {metric.field_names.map((field) => (
                  <div className="field-row" key={field}>
                    <span className="field-label">{field}:</span>
                    <span className="field-value">{formatValue(field, row[field])}</span>
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import axios from "axios";
import WalletBalanceChart from "./ChartminiComponents/WalletBalanceChart";
import GamePlayDaysChart from "./ChartminiComponents/GamePlayDaysChart";
import CommissionChart from "./ChartminiComponents/other/CommissionChart";
import "./Charts.css";

export default function Charts() {
  const [tables, setTables] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchTables() {
      try {
        const res = await axios.get("http://localhost:3000/api/charts");
        setTables(res.data.results);
      } catch (err) {
        console.error("Failed fetching charts:", err);
      } finally {
        setLoading(false);
      }
    }
    fetchTables();
  }, []);

  if (loading) return <h1 className="loading">Loading charts...</h1>;

  function getNeededCols(data, xaxis, yaxis) {
    if ((xaxis = "date_")) {
      return data.map((row) => ({
        _x: row["date_"].split("T")[0],
        _y: Number(row[yaxis]) || 0,
      }));
    } else {
      return data.map((row) => ({
        _x: row[xaxis] || "Unknown",
        _y: Number(row[yaxis]) || 0,
      }));
    }
  }

  return (
    <div className="charts-root">
      <h1 className="charts-title">Analytics Dashboard</h1>

      <div className="charts-grid">
        {tables.map((table, index) => {
          const type = table.chart_type;
          const data = table.data ?? [];

          return (
            <div className="chart-card" key={index}>
              <h2 className="chart-card-title">{table.metric_name || "Chart"}</h2>

              {type === "bar_chart" && <WalletBalanceChart data={getNeededCols(data, "email", "total_balance")} />}
              {type === "bar_chart" && <WalletBalanceChart data={getNeededCols(data, "date_", "remainder_you_keep_32pct")} />}
              {type === "line_chart" && <GamePlayDaysChart data={getNeededCols(data, "date_", "total_sessions")} />}
            </div>
          );
        })}
      </div>
    </div>
  );
}

import pickle
import math
from collections import defaultdict

def load_preprocessed_documents():
    with open('preprocessed_documents.pkl', 'rb') as f:
        preprocessed_documents = pickle.load(f)
    return preprocessed_documents

def build_inverted_index(preprocessed_documents):
    inverted_index = defaultdict(dict)
    doc_term_counts = {}
    total_documents = len(preprocessed_documents)

    # Build inverted index and term frequencies
    for doc_id, terms in preprocessed_documents.items():
        term_counts = {}
        for term in terms:
            term_counts[term] = term_counts.get(term, 0) + 1
        doc_term_counts[doc_id] = term_counts
        for term, count in term_counts.items():
            if doc_id not in inverted_index[term]:
                inverted_index[term][doc_id] = count

    idf = {}
    for term, doc_list in inverted_index.items():
        idf[term] = math.log(total_documents / len(doc_list))

    return inverted_index, idf, doc_term_counts

if __name__ == '__main__':
    preprocessed_documents = load_preprocessed_documents()
    inverted_index, idf, doc_term_counts = build_inverted_index(preprocessed_documents)

    # Save for later use
    with open('inverted_index.pkl', 'wb') as f:
        pickle.dump(inverted_index, f)
    with open('idf.pkl', 'wb') as f:
        pickle.dump(idf, f)
    with open('doc_term_counts.pkl', 'wb') as f:
        pickle.dump(doc_term_counts, f)

